#include<bits/stdc++.h>
using namespace std;
int f[200][200]={0};
int main()
{
    int n,a;
    cin>>n;
    for(int i=1;i<=n;++i)
    {
        cin>>a;
        for(int j=1;j<=a;++j)
        {
            f[i][j]=INT_MAX/2;
            int b,c;
            cin>>b;
            while(b!=0)
            {
                cin>>c;
                f[i][j]=f[i-1][b]+c<f[i][j]?f[i-1][b]+c:f[i][j];
                cin>>b;
            }
        }
    }
    int min=INT_MAX;
    for(int i=1;i<=a;++i)
        min=f[n][i]<min?f[n][i]:min;
    cout<<min;
    return 0;
}
